exercises.solutionCode:
function recommendSettings(task) {
  const normalized = task.toLowerCase();
  if (normalized.includes("extract")) return { temperature: 0.1, reason: "factual extraction" };
  if (normalized.includes("brainstorm")) return { temperature: 0.8, reason: "creative exploration" };
  if (normalized.includes("summarize")) return { temperature: 0.2, reason: "faithful summary" };
  return { temperature: 0.3, reason: "balanced task" };
}
